-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH aar_base_data AS (
    SELECT
        EQPMNT_ID,
        MARK_CD,
        EQPUN_NBR,
        AAR_CAR_CD,
        AAR_CAR_CODE_ID,
        EQPMNT_GROUP_CD,
        AXLE_QTY,
        BUILT_DT,
        DMTR_UOM_BASIS_CD,
        EIN_NBR,
        GROSS_WEIGHT_QTY,
        GROSS_WEIGHT_UOM_BASIS_CD,
        LINEAL_FRCTNL_UOM_BASIS_CD,
        LINEAL_UOM_BASIS_CD,
        LIQUID_UOM_BASIS_CD,
        OTSD_EXTRM_HEIGHT_QTY,
        OTSD_EXTRM_WIDTH_QTY,
        OTSD_HEIGHT_EXTRM_WIDTH_QTY,
        OTSD_LENGTH_QTY,
        OWNER_MARK_CD,
        PRIOR_EQPUN_NBR,
        PRIOR_MARK_CD,
        SPEED_UOM_BASIS_CD,
        STATUS_CD,
        SRVC_LIFE_CD,
        STNCL_MARK_OWNER_CLASS_CD,
        TARE_WEIGHT_QTY,
        VOLUME_UOM_BASIS_CD,
        WEIGHT_UOM_BASIS_CD,
        MCHNCL_DSGNTN_CD,
        PLATE_CLRNC_CD,
        RBLT_CD,
        RBLT_DT,
        RATE_CD,
        EFCTV_TMS,
        DLTD_TMS,
        RECORD_CREATE_TMS,
        'Y' AS SRC_REGSTRD
    FROM {{ ref('int_eqpmnt_aar_base_filtered') }}
),

non_rgstrd_data AS (
    SELECT
        NULL AS EQPMNT_ID,
        MARK_CD,
        EQPUN_NBR,
        NULL AS AAR_CAR_CD,
        NULL AS AAR_CAR_CODE_ID,
        NULL AS EQPMNT_GROUP_CD,
        NULL AS AXLE_QTY,
        NULL AS BUILT_DT,
        NULL AS DMTR_UOM_BASIS_CD,
        NULL AS EIN_NBR,
        NULL AS GROSS_WEIGHT_QTY,
        NULL AS GROSS_WEIGHT_UOM_BASIS_CD,
        NULL AS LINEAL_FRCTNL_UOM_BASIS_CD,
        NULL AS LINEAL_UOM_BASIS_CD,
        NULL AS LIQUID_UOM_BASIS_CD,
        NULL AS OTSD_EXTRM_HEIGHT_QTY,
        NULL AS OTSD_EXTRM_WIDTH_QTY,
        NULL AS OTSD_HEIGHT_EXTRM_WIDTH_QTY,
        NULL AS OTSD_LENGTH_QTY,
        NULL AS OWNER_MARK_CD,
        NULL AS PRIOR_EQPUN_NBR,
        NULL AS PRIOR_MARK_CD,
        NULL AS SPEED_UOM_BASIS_CD,
        NULL AS STATUS_CD,
        NULL AS SRVC_LIFE_CD,
        NULL AS STNCL_MARK_OWNER_CLASS_CD,
        NULL AS TARE_WEIGHT_QTY,
        NULL AS VOLUME_UOM_BASIS_CD,
        NULL AS WEIGHT_UOM_BASIS_CD,
        NULL AS MCHNCL_DSGNTN_CD,
        NULL AS PLATE_CLRNC_CD,
        NULL AS RBLT_CD,
        NULL AS RBLT_DT,
        NULL AS RATE_CD,
        NULL AS EFCTV_TMS,
        NULL AS DLTD_TMS,
        RECORD_CREATE_TMS,
        'N' AS SRC_REGSTRD
    FROM {{ ref('int_eqpmnt_non_rgstrd_filtered') }}
),

combined_data AS (
    SELECT * FROM aar_base_data
    UNION ALL
    SELECT * FROM non_rgstrd_data
),

dim_equipment_lookup AS (
    SELECT
        DIM_EQUIPMENT_ID,
        EQPUN_NBR,
        MARK_CD,
        EDW_START_EFCTV_DT,
        EDW_END_EFCTV_DT,
        EDW_CURRENT_FLG
    FROM {{ ref('stg_dim_equipment') }}
),

pool_assignments AS (
    SELECT
        EQPMNT_ID,
        EQPMNT_POOL_ID AS lkp_EQPMNT_POOL_ID,
        FLEET_NM AS lkp_FLEET_NM,
        FLEET_SBGRP_CTGRY_NM AS lkp_FLEET_SBGRP_CTGRY_NM,
        PARTY_NM AS lkp_PARTY_NM,
        TARGET_EQPMT_CTGRY_NM AS lkp_TARGET_EQPMT_CTGRY_NM,
        PRDCT_NM AS lkp_PRDCT_NM
    FROM {{ ref('int_eqpmnt_pool_assignments') }}
),

final_data AS (
    SELECT
        cd.*,
        del.DIM_EQUIPMENT_ID AS o_DIM_EQUIPMENT_ID,
        del.EDW_START_EFCTV_DT AS o_EDW_START_EFCTV_DT,
        del.EDW_END_EFCTV_DT AS o_EDW_END_EFCTV_DT,
        del.EDW_CURRENT_FLG AS o_EDW_CURRENT_FLG,
        pa.lkp_EQPMNT_POOL_ID,
        pa.lkp_FLEET_NM,
        pa.lkp_FLEET_SBGRP_CTGRY_NM,
        pa.lkp_PARTY_NM,
        pa.lkp_TARGET_EQPMT_CTGRY_NM,
        pa.lkp_PRDCT_NM,
        NULL AS o_LESSEE_MARK_CD,
        NULL AS o_CAR_KIND_CD,
        NULL AS UCA_CODES,
        NULL AS CPR_EQPMT_POOL_ID,
        NULL AS AAR_EQPMNT_POOL_ID,
        NULL AS CAR_OWNERSHIP,
        NULL AS LEASED_IND,
        NULL AS REGISTERED_IND,
        NULL AS CP_OWNED_IND,
        CASE
            WHEN del.DIM_EQUIPMENT_ID IS NULL THEN 'I'
            WHEN del.EDW_CURRENT_FLG = 'Y' THEN 'U'
            ELSE 'I'
        END AS I_U_FLG,
        CASE
            WHEN del.DIM_EQUIPMENT_ID IS NOT NULL
                 AND del.EDW_CURRENT_FLG = 'Y'
                 AND (cd.STATUS_CD != 'A' OR cd.DLTD_TMS IS NOT NULL) THEN '2'
            ELSE '1'
        END AS TYPE_2_FLG,
        CASE
            WHEN del.EDW_END_EFCTV_DT IS NULL THEN DATEADD('SECOND', -1, CURRENT_TIMESTAMP())
            ELSE del.EDW_END_EFCTV_DT
        END AS TYPE2_END_EFFECTV_DT
    FROM combined_data cd
    LEFT JOIN dim_equipment_lookup del
        ON TRIM(cd.MARK_CD) = TRIM(del.MARK_CD)
        AND TRIM(cd.EQPUN_NBR) = TRIM(del.EQPUN_NBR)
        AND del.EDW_CURRENT_FLG = 'Y'
    LEFT JOIN pool_assignments pa
        ON cd.EQPMNT_ID = pa.EQPMNT_ID
)

SELECT * FROM final_data
